create table saldos_iniciales
(
    saldoinicial numeric(15, 2),
    mes          integer              not null,
    semana       integer              not null,
    banco        varchar              not null,
    moneda_ref   varchar              not null,
    tasa_mes     numeric(15, 2),
    fecha        date,
    saldo_usd    numeric(15, 2),
    ano          integer default 2025 not null,
    constraint saldos_iniciales_pk
        primary key (ano, mes, semana, banco, moneda_ref)
);

alter table saldos_iniciales
    owner to postgres;

